diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..e07f3fa21db5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3396,6 +3396,44 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     return SelectInst::Create(FalseVal, One, AndV);
   }

+  // select (not X), Y, false -> false  if X is equivalent to Y
+  // select (not X), true, Y -> true    if X is equivalent to Y
+  // When the condition is the negation of a value X, and the true value Y
+  // is equivalent to X, and the false value is false, the result is always false.
+  // Similarly, if the true value is true and the false value is equivalent to X,
+  // the result is always true.
+  Value *NotX;
+  if (match(CondVal, m_Not(m_Value(NotX)))) {
+    if (match(FalseVal, m_Zero())) {
+      // Check if NotX is equivalent to TrueVal
+      // This handles cases like:
+      //   %1 = trunc nuw (lshr %0, 31) to i1
+      //   %2 = icmp slt %0, 0
+      //   select (xor %1, true), %2, false -> false
+      Value *V;
+      if (match(NotX, m_NUWTrunc(m_Value(V))) &&
+          match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(V),
+                                        m_Zero())))
+        return replaceInstUsesWith(SI, Zero);
+      // Also check the reverse: TrueVal is trunc nuw, NotX is icmp slt
+      if (match(TrueVal, m_NUWTrunc(m_Value(V))) &&
+          match(NotX, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(V),
+                                     m_Zero())))
+        return replaceInstUsesWith(SI, Zero);
+    }
+    if (match(TrueVal, m_One())) {
+      Value *V;
+      if (match(NotX, m_NUWTrunc(m_Value(V))) &&
+          match(FalseVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(V),
+                                         m_Zero())))
+        return replaceInstUsesWith(SI, One);
+      if (match(FalseVal, m_NUWTrunc(m_Value(V))) &&
+          match(NotX, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(V),
+                                     m_Zero())))
+        return replaceInstUsesWith(SI, One);
+    }
+  }
+
   if (match(FalseVal, m_Zero()) || match(TrueVal, m_One())) {
     Use *Y = nullptr;
     bool IsAnd = match(FalseVal, m_Zero()) ? true : false;

